#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=200005<<5;
int n,m,cnt,a[N],b[N];
int tr[N],ls[N],rs[N],num[N];
void push_up(int id)
{
	tr[id]=tr[ls[id]]+tr[rs[id]];
}
int build(int x,int y)
{
	int id=++cnt;
	if(x==y)
	{
		return id;
	}
	int mid=(x+y)/2;
	ls[id]=build(x,mid);
	rs[id]=build(mid+1,y);
	return id;
}
int update(int id,int x,int y,int z)
{
	tr[++cnt]=tr[id];
	ls[cnt]=ls[id];
	rs[cnt]=rs[id];
	int tmp=id;
	id=cnt;
	if(x==y)
	{
		tr[id]=tr[tmp]+1;
		return id;
	}
	int mid=(x+y)/2;
	if(z<=mid) ls[id]=update(ls[id],x,mid,z);
	else rs[id]=update(rs[id],mid+1,y,z);
	push_up(id);
	return id;
}
int query(int id,int id2,int x,int y,int z)
{
	if(x==y) return x;
	int mid=(x+y)/2,tmp=tr[ls[id2]]-tr[ls[id]];
	if(z<=tmp) return query(ls[id],ls[id2],x,mid,z);
	else return query(rs[id],rs[id2],mid+1,y,z-tmp);
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
