	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
		b[i]=a[i];
	}
	sort(b+1,b+1+n);
	int len=unique(b+1,b+1+n)-b-1;
	num[0]=1;
	build(1,len);
	for(int i=1;i<=n;i++)
	{
		int tmp=lower_bound(b+1,b+1+len,a[i])-b;
		num[i]=cnt+1;
		update(num[i-1],1,len,tmp);
	}
	while(m--)
	{
		int l,r,z;
		cin>>l>>r>>z;
